external_knowledge:
- 'navigators' refers to employees;
- 'charted their way through the sea of knowledge' refers to completed training;
- 'compass directions' metaphorically represents the job titles and departments;
- 'fleet of courses' is a metaphor for training courses completed;
- 'sparkle' is a metaphor for the evaluation score in this context.

sql:
SELECT COUNT(DISTINCT employee_id) AS 'Number of Employees'
FROM employee_training
WHERE training_id > 5;

SELECT e.id, e.job_title, esl.skill_level_id
FROM employees e
LEFT JOIN employee_skill_levels esl ON e.id = esl.employee_id;

SELECT COUNT(*) AS total_employees_completed_training
FROM employee_training
WHERE training_status = 'Completed';

SELECT COUNT(DISTINCT employee_id)
FROM employee_training
WHERE training_status = 'Completed';

SELECT COUNT(DISTINCT et.employee_id) AS unique_completed_trainees
FROM employee_training et
WHERE et.training_status = 'Completed';
